import{_ as t,o,c as a,a4 as r}from"./chunks/framework.Cqne-ChA.js";const d=JSON.parse('{"title":"Meet the zopen Team","description":"","frontmatter":{},"headers":[],"relativePath":"team.md","filePath":"team.md","lastUpdated":1753976621000}'),i={name:"team.md"};function n(s,e,l,h,u,m){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="meet-the-zopen-team" tabindex="-1">Meet the zopen Team <a class="header-anchor" href="#meet-the-zopen-team" aria-label="Permalink to &quot;Meet the zopen Team&quot;">​</a></h1><p>Welcome! We&#39;re the Technical Steering Committee (TSC) for the zopen community. We&#39;re a group of passionate individuals dedicated to guiding the technical direction and fostering a vibrant open-source community for z/OS.</p><h2 id="our-mission" tabindex="-1">Our Mission <a class="header-anchor" href="#our-mission" aria-label="Permalink to &quot;Our Mission&quot;">​</a></h2><p>Our primary goal is to make z/OS a more open and accessible platform for everyone. We do this by:</p><ul><li>Curating a rich ecosystem of popular open-source tools.</li><li>Supporting developers and contributors in the community.</li><li>Ensuring the long-term health and stability of the zopen commmunity.</li><li>Making it easier for everyone to contribute to and use open source on the mainframe.</li></ul><h2 id="meet-the-members" tabindex="-1">Meet the Members <a class="header-anchor" href="#meet-the-members" aria-label="Permalink to &quot;Meet the Members&quot;">​</a></h2><p>The zopen community TSC is composed of the following members:</p><ul><li>Igor Todorovski</li><li>Haritha D</li><li>Mike Fulton</li><li>Vignesh S</li><li>Gary Grossi</li><li>Lionel Dyck</li><li>Haritha D</li><li>Russell Wilson</li><li>Anthony Giorgio</li><li>Erik Janssen</li><li>Sachin T</li></ul><h2 id="tsc-meeting-minutes" tabindex="-1">TSC Meeting Minutes <a class="header-anchor" href="#tsc-meeting-minutes" aria-label="Permalink to &quot;TSC Meeting Minutes&quot;">​</a></h2><p>You can find the minutes from our TSC development meetings <a href="https://github.com/zopencommunity/meta/wiki/Development-Minutes" target="_blank" rel="noreferrer">here</a>.</p><h2 id="our-contributors" tabindex="-1">Our Contributors <a class="header-anchor" href="#our-contributors" aria-label="Permalink to &quot;Our Contributors&quot;">​</a></h2><p>We are incredibly grateful for our amazing community of contributors. You can see a list of all the people who have contributed to the zopen project <a href="https://insights.linuxfoundation.org/project/zopen/contributors" target="_blank" rel="noreferrer">here</a>.</p><h2 id="how-we-work" tabindex="-1">How We Work <a class="header-anchor" href="#how-we-work" aria-label="Permalink to &quot;How We Work&quot;">​</a></h2><p>We meet regularly to discuss the project&#39;s roadmap, review contributions, and tackle technical challenges. Our doors are always open for community <a href="https://github.com/zopencommunity/meta/issues" target="_blank" rel="noreferrer">feedback</a> and <a href="https://github.com/orgs/zopencommunity/discussions" target="_blank" rel="noreferrer">ideas</a>.</p><h2 id="get-in-touch" tabindex="-1">Get in Touch <a class="header-anchor" href="#get-in-touch" aria-label="Permalink to &quot;Get in Touch&quot;">​</a></h2><p>Have a question, an idea, or want to get more involved? The best way to reach us is through the <a href="https://github.com/orgs/zopencommunity/discussions" target="_blank" rel="noreferrer">community discussions forum</a>. We&#39;d love to hear from you!</p>',16)])])}const p=t(i,[["render",n]]);export{d as __pageData,p as default};
